macro.implementation:
do {
  osalSysLockFromISR();
  if ((adcp)->sync_state == (state)) {
    osalThreadResumeI(&(adcp)->thread, MSG_OK);
  }
  osalSysUnlockFromISR();
} while (false)

do {
  osalSysLockFromISR();
  osalThreadResumeI(&(adcp)->thread, MSG_RESET);
  osalSysUnlockFromISR();
} while (false)

do {
  (adcp)->events |= ADC_EVENT_HALF;
  __cbdrv_invoke_cb_with_transition(adcp,
                                    HAL_DRV_STATE_HALF,
                                    ADC_ACTIVE_CIRCULAR);
  _adc_wakeup_isr(adcp, HAL_DRV_STATE_HALF);
} while (false)

do {
  if ((adcp)->state == ADC_ACTIVE_CIRCULAR) {
    (adcp)->events |= ADC_EVENT_FULL;
    __cbdrv_invoke_cb_with_transition(adcp,
                                      HAL_DRV_STATE_FULL,
                                      ADC_ACTIVE_CIRCULAR);
    _adc_wakeup_isr(adcp, HAL_DRV_STATE_FULL);
  }
  else {
    adc_lld_stop_conversion(adcp);
    (adcp)->events |= ADC_EVENT_COMPLETE;
    __cbdrv_invoke_cb_with_transition(adcp,
                                      HAL_DRV_STATE_COMPLETE,
                                      HAL_DRV_STATE_READY);
    (adcp)->grpp = NULL;
    _adc_wakeup_isr(adcp, HAL_DRV_STATE_COMPLETE);
  }
} while (false)

do {
  adc_lld_stop_conversion(adcp);
  (adcp)->errors |= (err);
  __cbdrv_invoke_cb_with_transition(adcp,
                                    HAL_DRV_STATE_ERROR,
                                    HAL_DRV_STATE_READY);
  (adcp)->grpp = NULL;
  _adc_error_wakeup_isr(adcp);
} while (false)

types.verbatim:
/* Including the low level driver header, it exports information required
   for completing types.*/
#include "hal_adc_lld.h"

objinit.implementation:
self->samples = NULL;
self->depth   = 0U;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;
#if ADC_USE_SYNCHRONIZATION == TRUE
self->thread     = NULL;
self->sync_state = HAL_DRV_STATE_STOP;
#endif

method.implementation:
msg_t msg;

osalDbgCheckClassI();
osalDbgCheck((self != NULL) && (samples != NULL) &&
             (depth > 0U) && ((depth == 1U) || ((depth & 1U) == 0U)));
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == HAL_DRV_STATE_ERROR),
              "not ready");

self->samples = samples;
self->depth   = depth;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;
self->state   = ADC_ACTIVE_LINEAR;
msg = adc_lld_start_conversion(self, grpnum, samples, depth);
if (msg != HAL_RET_SUCCESS) {
  self->samples = NULL;
  self->depth   = 0U;
  self->grpp    = NULL;
  self->state   = HAL_DRV_STATE_READY;
}

return msg;

msg_t msg;

osalSysLock();
msg = adcStartConversionLinearI(self, grpnum, samples, depth);
osalSysUnlock();

return msg;

msg_t msg;

osalDbgCheckClassI();
osalDbgCheck((self != NULL) && (samples != NULL) &&
             (depth > 0U) && ((depth == 1U) || ((depth & 1U) == 0U)));
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == HAL_DRV_STATE_ERROR),
              "not ready");

self->samples = samples;
self->depth   = depth;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;
self->state   = ADC_ACTIVE_CIRCULAR;
msg = adc_lld_start_conversion(self, grpnum, samples, depth);
if (msg != HAL_RET_SUCCESS) {
  self->samples = NULL;
  self->depth   = 0U;
  self->grpp    = NULL;
  self->state   = HAL_DRV_STATE_READY;
}

return msg;

msg_t msg;

osalSysLock();
msg = adcStartConversionCircularI(self, grpnum, samples, depth);
osalSysUnlock();

return msg;

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == ADC_ACTIVE_LINEAR) ||
              (self->state == ADC_ACTIVE_CIRCULAR) ||
              (self->state == HAL_DRV_STATE_HALF) ||
              (self->state == HAL_DRV_STATE_FULL) ||
              (self->state == HAL_DRV_STATE_COMPLETE) ||
              (self->state == HAL_DRV_STATE_ERROR),
              "invalid state");

if (self->state != HAL_DRV_STATE_READY) {
  adc_lld_stop_conversion(self);
  self->samples = NULL;
  self->depth   = 0U;
  self->grpp    = NULL;
  self->state   = HAL_DRV_STATE_READY;
  _adc_reset_i(self);
}

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == ADC_ACTIVE_LINEAR) ||
              (self->state == ADC_ACTIVE_CIRCULAR) ||
              (self->state == HAL_DRV_STATE_HALF) ||
              (self->state == HAL_DRV_STATE_FULL) ||
              (self->state == HAL_DRV_STATE_COMPLETE) ||
              (self->state == HAL_DRV_STATE_ERROR),
              "invalid state");
if (self->state != HAL_DRV_STATE_READY) {
  adc_lld_stop_conversion(self);
  self->samples = NULL;
  self->depth   = 0U;
  self->grpp    = NULL;
  self->state   = HAL_DRV_STATE_READY;
  _adc_reset_s(self);
}
osalSysUnlock();

msg_t msg;

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert(self->thread == NULL, "already waiting");
msg = adcStartConversionLinearI(self, grpnum, samples, depth);
if (msg == HAL_RET_SUCCESS) {
  msg = adcSynchronizeStateS(self, HAL_DRV_STATE_COMPLETE, TIME_INFINITE);
}
osalSysUnlock();

return msg;

msg_t msg;

osalDbgCheck(self != NULL);
osalDbgCheckClassS();
osalDbgCheck((state == HAL_DRV_STATE_HALF) ||
             (state == HAL_DRV_STATE_FULL) ||
             (state == HAL_DRV_STATE_COMPLETE));
osalDbgAssert((self->state == ADC_ACTIVE_LINEAR) ||
              (self->state == ADC_ACTIVE_CIRCULAR),
              "invalid state");
osalDbgAssert(self->thread == NULL, "already waiting");

self->sync_state = state;
msg = osalThreadSuspendTimeoutS(&self->thread, timeout);
self->sync_state = HAL_DRV_STATE_STOP;

return msg;

msg_t msg;

osalDbgCheck(self != NULL);

osalSysLock();
msg = adcSynchronizeStateS(self, state, timeout);
osalSysUnlock();

return msg;

adceventflags_t flags;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
flags = self->events & mask;
self->events &= ~mask;
osalSysRestoreStatusX(sts);

return flags;

adcerror_t errors;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
errors = self->errors & mask;
self->errors &= ~mask;
osalSysRestoreStatusX(sts);

return errors;

msg_t msg;

self->config = __adc_setcfg_impl(self, config);
if (self->config == NULL) {
  return HAL_RET_CONFIG_ERROR;
}

self->samples = NULL;
self->depth   = 0U;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;

msg = adc_lld_start(self);
if (msg != HAL_RET_SUCCESS) {
  self->config = NULL;
}

return msg;

adc_lld_stop(self);
self->samples = NULL;
self->depth   = 0U;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;
